GROQ_MODEL = "llama-3.3-70b-versatile"

def analizar_con_groq(prompt: str, max_tokens: int = 2000) -> str:
    import requests as _req
    if not GROQ_API_KEY:
        return "⚠️ GROQ_API_KEY vacía."
    try:
        resp = _req.post(
            GROQ_URL,
            headers={"Authorization": f"Bearer {GROQ_API_KEY}",
                     "Content-Type": "application/json"},
            json={
                "model": GROQ_MODEL,
                "messages": [
                    {"role": "system", "content": (
                        "Eres un analista experto en rendimiento y prevención de lesiones "
                        "en fútbol profesional. Respondes SIEMPRE en español claro, "
                        "con rigor científico y recomendaciones prácticas para el cuerpo técnico."
                    )},
                    {"role": "user", "content": prompt},
                ],
                "max_tokens": max_tokens,
                "temperature": 0.4,
            },
            timeout=60,
        )
        if resp.status_code == 401: return "⚠️ API Key inválida (401)."
        if resp.status_code == 429: return "⚠️ Límite de Groq alcanzado. Esperá unos segundos."
        if resp.status_code >= 400: return f"⚠️ Error HTTP {resp.status_code}: {resp.text[:300]}"
        return resp.json()["choices"][0]["message"]["content"].strip()
    except _req.exceptions.Timeout:      return "⚠️ Timeout (60s). Intentá de nuevo."
    except _req.exceptions.ConnectionError: return "⚠️ Sin conexión a Internet."
    except Exception as e:               return f"⚠️ Error inesperado: {e}"

