import os
from functools import wraps
import hashlib
import json

# Intentar importar flask_caching, si no está disponible usar fallback
try:
    from flask_caching import Cache
    FLASK_CACHING_DISPONIBLE = True
    logger.info("✅ Flask-Caching detectado y cargado")
except ImportError:
    FLASK_CACHING_DISPONIBLE = False
    logger.warning("⚠️ Flask-Caching no disponible - Usando caché simple en memoria")

    # Implementación simple de caché en memoria como fallback
    class SimpleMemoryCache:
        def __init__(self):
            self._cache = {}

        def memoize(self, timeout=3600):
            """Decorador simple de caché en memoria"""
            def decorator(func):
                @wraps(func)
                def wrapper(*args, **kwargs):
                    # Crear key basada en función y argumentos
                    cache_key = f"{func.__name__}_{hashlib.md5(str(args).encode() + str(kwargs).encode()).hexdigest()}"

                    # Verificar si está en caché
                    if cache_key in self._cache:
                        return self._cache[cache_key]

                    # Ejecutar función y guardar en caché
                    result = func(*args, **kwargs)
                    self._cache[cache_key] = result
                    return result
                return wrapper
            return decorator

        def clear(self):
            """Limpiar todo el caché"""
            self._cache.clear()
            return True

        def delete_memoized(self, func_name):
            """Limpiar caché de una función específica"""
            keys_to_delete = [k for k in self._cache.keys() if k.startswith(func_name)]
            for key in keys_to_delete:
                del self._cache[key]
            return True

    # Clase wrapper para mantener compatibilidad con Flask-Caching
    class Cache:
        def __init__(self, app_server=None, config=None):
            self._simple_cache = SimpleMemoryCache()
            if config:
                logger.info(f"ℹ️ Configuración de caché recibida (modo fallback): {config.get('CACHE_TYPE', 'SimpleMemory')}")

        def memoize(self, timeout=3600):
            return self._simple_cache.memoize(timeout)

        def clear(self):
            return self._simple_cache.clear()

        def delete_memoized(self, func):
            return self._simple_cache.delete_memoized(func.__name__ if callable(func) else func)

