# @hooks.routing() NO DISPONIBLE EN DASH - Función helper normal
def custom_routing_logic(pathname):
    """
    Control avanzado de navegación entre visualizaciones.
    Registra cada cambio de página en el historial de la sesión.
    """
    try:
        # Registrar la navegación en el historial
        config_manager.add_to_history("page_view", {"path": pathname, "timestamp": datetime.now().isoformat()})

        # Log de navegación
        logger.info(f"🧭 Navegación registrada: {pathname}")

        # Validar pathname antes de retornar
        if pathname and pathname.startswith('/'):
            return pathname
        else:
            # Si el pathname no es válido, retornar al dashboard
            return '/'
    except Exception as e:
        logger.warning(f"⚠️ Error en routing hook: {e}")
        return pathname

