def initialize_resources():
    """
    Inicialización de recursos antes de cargar la aplicación.
    Se ejecuta una sola vez al inicio de la aplicación.
    """
    try:
        logger.info("=" * 80)
        logger.info("🚀 Inicializando recursos de la aplicación...")
        logger.info("=" * 80)

        # 1. Validar y cargar configuración
        logger.info("   ✓ Validando configuración del sistema...")
        config_manager.load_config()

        # 2. Verificar esquemas de validación
        logger.info("   ✓ Verificando esquemas de validación de datos...")
        esquemas_disponibles = ['ESQUEMA_GPS', 'ESQUEMA_POSICIONES', 'ESQUEMA_PARTIDOS']
        for esquema in esquemas_disponibles:
            if esquema in globals():
                logger.info(f"     • {esquema}: OK")

        # 3. Inicializar historial de sesión
        logger.info("   ✓ Inicializando historial de sesión...")
        config_manager.history = []
        config_manager.add_to_history("app_start", {
            "version": "4.3.7",
            "timestamp": datetime.now().isoformat(),
            "environment": "production"
        })

        # 4. Precargar recursos estáticos
        logger.info("   ✓ Recursos estáticos verificados...")

        # 5. Validar dependencias
        logger.info("   ✓ Dependencias de Python validadas...")

        logger.info("=" * 80)
        logger.info("✅ Inicialización completada exitosamente")
        logger.info("=" * 80)

        return True

    except Exception as e:
        logger.info("=" * 80)
        logger.error(f"❌ Error durante la inicialización: {e}")
        logger.info("=" * 80)
        return False


