def manejar_errores_callback(nombre_viz=None):
    """
    Decorador que envuelve callbacks para manejar errores automáticamente.

    BENEFICIOS:
    - La app NUNCA se cae por un error en un callback
    - Logs automáticos de errores con stack trace completo
    - Mensajes amigables al usuario
    - Medición de rendimiento automática

    USO:
        @manejar_errores_callback(nombre_viz="VIZ 1 - Media Móvil")
        def update_v1(n, data, atleta, metrica, ...):
            # Tu código aquí
            pass

    Args:
        nombre_viz: Nombre descriptivo de la visualización

    Returns:
        Función decorada con manejo de errores
    """
    def decorador(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            inicio = time.time()
            nombre = nombre_viz or func.__name__

            try:
                # Log de inicio
                logger.debug(f"▶️  [{nombre}] Iniciando callback...")

                # Ejecutar función original
                resultado = func(*args, **kwargs)

                # Calcular tiempo de ejecución
                tiempo_ejecucion = (time.time() - inicio) * 1000  # ms

                # Log de éxito con rendimiento
                if tiempo_ejecucion < 500:
                    nivel_emoji = "⚡"
                    nivel_msg = "RÁPIDO"
                elif tiempo_ejecucion < 2000:
                    nivel_emoji = "✓"
                    nivel_msg = "OK"
                else:
                    nivel_emoji = "🐢"
                    nivel_msg = "LENTO"

                logger.info(
                    f"{nivel_emoji} [{nombre}] Completado | "
                    f"Tiempo: {tiempo_ejecucion:.0f}ms | "
                    f"Estado: {nivel_msg}"
                )

                # Si hay caché activo, registrar beneficio
                if CACHE_DISPONIBLE and tiempo_ejecucion < 300:
                    logger.debug(f"💾 [{nombre}] Beneficio de caché detectado")

                return resultado

            except Exception as e:
                logger.debug(f"Excepción capturada: {e}")
                # Calcular tiempo hasta el error
                tiempo_error = (time.time() - inicio) * 1000

                # Log detallado del error
                logger.error(f"❌ [{nombre}] ERROR después de {tiempo_error:.0f}ms")
                logger.error(f"❌ [{nombre}] Tipo: {type(e).__name__}")
                logger.error(f"❌ [{nombre}] Mensaje: {str(e)}")

                # Stack trace completo en DEBUG
                logger.debug(f"❌ [{nombre}] Stack trace:\n{traceback.format_exc()}")

                # Mensaje amigable al usuario
                mensaje_usuario = html.Div([
                    html.Div([
                        html.I(className="fas fa-exclamation-triangle", 
                              style={"fontSize": "48px", "color": "#EF4444", "marginBottom": "16px"}),
                        html.H3("Ocurrió un Error", 
                               style={"color": "#1F2937", "fontWeight": "800", "marginBottom": "12px"}),
                        html.P(f"Visualización: {nombre}", 
                              style={"fontSize": "16px", "color": "#6B7280", "marginBottom": "8px"}),
                        html.P(f"Error: {type(e).__name__}", 
                              style={"fontSize": "14px", "color": "#9CA3AF", "marginBottom": "20px"}),
                        html.Div([
                            html.Strong("¿Qué hacer?"),
                            html.Ul([
                                html.Li("Verifica que los datos estén cargados correctamente"),
                                html.Li("Intenta actualizar la página (F5)"),
                                html.Li("Si el error persiste, revisa el archivo de logs: tfm_gps_pro.log"),
                            ], style={"textAlign": "left", "display": "inline-block"})
                        ], style={"fontSize": "13px", "color": "#4B5563", "textAlign": "left"})
                    ], style={
                        "textAlign": "center",
                        "padding": "48px 32px",
                        "backgroundColor": "#FEE2E2",
                        "borderRadius": "16px",
                        "border": "3px solid #EF4444",
                        "boxShadow": "0 8px 24px rgba(239, 68, 68, 0.3)",
                        "maxWidth": "600px",
                        "margin": "40px auto"
                    })
                ], style={"padding": "20px"})

                return mensaje_usuario

        return wrapper
    return decorador

