def log_uso_cache(nombre_funcion, fue_cache_hit):
    """
    Registra uso del sistema de caché.

    Args:
        nombre_funcion: Nombre de la función que usó caché
        fue_cache_hit: True si se usó caché, False si se procesó desde cero
    """
    if fue_cache_hit:
        logger.debug(f"💾 [CACHÉ HIT] {nombre_funcion} | Datos recuperados de caché")
    else:
        logger.debug(f"🔄 [CACHÉ MISS] {nombre_funcion} | Procesando datos desde cero")

