                style_header={'backgroundColor': '#7c3aed', 'color': 'white', 'fontWeight': '800', 'fontSize': '12px', 'textTransform': 'uppercase'},
                style_data_conditional=style_conditions_mono,
                fixed_columns={'headers': True, 'data': 1},
